    "name": "lshr_of_add_of_boolean_like_values_to_and",
    "summary": "Fold a logical right shift by 1 of the sum of two boolean-like integer values into a bitwise and.",
    "match": {
      "root": "(lshr (add X, Y), 1)",
      "preconditions": [
        "X and Y have integer or integer-vector type of the same type as the add/lshr result",
        "For each lane, X is known to have at most 1 active bit",
        "For each lane, Y is known to have at most 1 active bit"
